Here's a simple C++ program that reads a text file line by line and counts the number of occurrences of a specific word in the file:

```cpp
#include <iostream>
#include <fstream>
#include <string>

int main() {
    std::string filename;
    std::string search_word;
    std::string line;
    int count = 0;

    // Ask for the file name and the word to search
    std::cout << "Enter the name of the text file: ";
    std::cin >> filename;
    std::cout << "Enter the word to count: ";
    std::cin >> search_word;

    // Open the input file
    std::ifstream input_file(filename);

    if (!input_file.is_open()) {
        std::cout << "Error opening the file." << std::endl;
        return 1;
    }

    // Read each line from the file and increment the count if the word is found
    while (getline(input_file, line)) {
        size_t pos = 0;
        while ((pos = line.find(search_word, pos)) != std::string::npos) {
            count++;
            pos += search_word.length();
        }
    }

    // Print the result
    std::cout << "The word \"" << search_word << "\" appears " << count << " times in the file." << std::endl;

    // Close the input file
    input_file.close();
    return 0;
}
```

